import { z } from "zod";
import { EDGE_MAP } from "./edge-map";

const binnedSchema = z
	.enum(["very_low", "low", "medium", "high", "very_high"])
	.describe(
		"Binned score category, can be used for interpretation, this is derived from the normalized score and the population distribution",
	);
type Binned = z.infer<typeof binnedSchema>;
// Number of bins (intervals) = edges.length - 1, constrained to 2..5
type IntervalCount = 2 | 3 | 4 | 5;

/**
 * Type guard to check if a number is a valid IntervalCount (2-5).
 */
function isValidIntervalCount(n: number): n is IntervalCount {
	return n >= 2 && n <= 5;
}

export function binScore(
	name: keyof typeof EDGE_MAP | string,
	normalized: number,
) {
	const edges = EDGE_MAP[name as keyof typeof EDGE_MAP] ?? [
		0, 0.2, 0.4, 0.6, 0.8, 1,
	];

	const rawIntervals = edges.length - 1;
	if (!isValidIntervalCount(rawIntervals)) {
		throw new Error(
			`Invalid number of edges for ${name}, must define between 3 and 6 edges to create 2 to 5 intervals.`,
		);
	}
	// rawIntervals is now narrowed to IntervalCount
	const intervals = rawIntervals;

	// Allowed label vocabulary (must match InterpretableScoreSchema enum)
	const LabelSets: Record<IntervalCount, readonly Binned[]> = {
		2: ["low", "high"],
		3: ["low", "medium", "high"],
		4: ["very_low", "low", "high", "very_high"],
		5: ["very_low", "low", "medium", "high", "very_high"],
	} as const;

	const labels = LabelSets[intervals];

	// Defensive copy + sort
	const sorted = [...edges].sort((a, b) => a - b);

	// Array bounds are guaranteed by the validation above (at least 3 edges = 2 intervals)
	const minEdge = sorted[0] ?? 0;
	const maxEdge = sorted.at(-1) ?? 1;
	const value = Math.min(Math.max(normalized, minEdge), maxEdge);

	// Bin selection - default to the last label (highest bin)
	// labels always has at least 2 elements based on LABEL_SETS definition
	const lastLabel = labels.at(-1) ?? "high";
	let binned: Binned = lastLabel;
	for (let i = 0; i < intervals; i++) {
		const upper = sorted[i + 1] ?? maxEdge;
		if (value <= upper) {
			binned = labels[i] ?? binned;
			break;
		}
	}

	return { binned, normalized };
}
