import { z } from "zod";
import { binScore } from "./bin-score";

export const InterpretableScoreSchema = z.object({
	binned: z
		.enum(["very_low", "low", "medium", "high", "very_high"])
		.describe(
			"Binned score category, can be used for interpretation, this is derived from the normalized score and the population distribution",
		),
	normalized: z
		.number()
		.gte(0)
		.lte(1)
		.describe("Normalized score from 0 to 1")
		.transform((n) => Math.round(n * 100) / 100),
});
export type InterpretableScoreSchema = z.infer<typeof InterpretableScoreSchema>;

