import * as LayeredLensesModel from "@mappa-ai/contracts/v1/layered-lenses";
import { z } from "zod";
import { ConduitError } from "../errors";
import type {
	BehaviorMapDirectUploadRequest,
	BehaviorMapDirectUploadResult,
	BehaviorMapExport,
} from "../internal-types";
import {
	DEFAULT_MAX_SOURCE_BYTES,
	materializeSource,
} from "../resources/source";
import type { Transport } from "../resources/transport";
import { parseRes } from "../resources/validate";

const behaviorMapExportResponse = z.object({
	behaviorMap: LayeredLensesModel.LayeredLenses,
	createdAt: z.iso.datetime(),
	entityId: z.string().min(1),
	mapId: z.string().min(1),
	modelCheckpoint: z.string().min(1),
});

const behaviorMapDirectUploadResponse = z.object({
	behaviorMap: LayeredLensesModel.LayeredLenses,
	modelCheckpoint: z.string().min(1),
	selectedSpeakerIndex: z.number().int().min(0),
});

function internalBehaviorMapsValidateSource(
	req: BehaviorMapDirectUploadRequest,
) {
	const keys = ["file", "url", "path"].filter((key) => key in req);
	if (keys.length === 1) {
		return req;
	}

	throw new ConduitError(
		"directUpload() must include exactly one of file, url, or path",
		{ code: "invalid_request" },
	);
}

function internalBehaviorMapsValidateTarget(
	target: BehaviorMapDirectUploadRequest["target"],
) {
	if (target.strategy === "dominant") {
		return target;
	}

	if (!target.hint.trim()) {
		throw new ConduitError("target.hint is required for magic_hint", {
			code: "invalid_request",
		});
	}

	return target;
}

export class InternalBehaviorMapsResource {
	private readonly transport: Transport;
	private readonly fetchImpl: typeof fetch;
	private readonly timeoutMs: number;
	private readonly maxSourceBytes: number;

	constructor(
		transport: Transport,
		opts?: {
			fetchImpl?: typeof fetch;
			timeoutMs?: number;
			maxSourceBytes?: number;
		},
	) {
		this.transport = transport;
		this.fetchImpl = opts?.fetchImpl ?? fetch;
		this.timeoutMs = opts?.timeoutMs ?? 300000;
		this.maxSourceBytes = opts?.maxSourceBytes ?? DEFAULT_MAX_SOURCE_BYTES;
	}

	async get(
		entityId: string,
		opts?: { requestId?: string; signal?: AbortSignal },
	): Promise<BehaviorMapExport> {
		if (!entityId) {
			throw new ConduitError("entityId must be a non-empty string", {
				code: "invalid_request",
			});
		}

		const res = await this.transport.request<BehaviorMapExport>({
			method: "GET",
			path: `/internal/behavior-maps/${encodeURIComponent(entityId)}`,
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});

		return parseRes(
			behaviorMapExportResponse,
			res.data,
			"internal.behaviorMaps.get",
		);
	}

	async directUpload(
		req: BehaviorMapDirectUploadRequest,
	): Promise<BehaviorMapDirectUploadResult> {
		if (typeof FormData === "undefined") {
			throw new ConduitError(
				"FormData is not available in this runtime; cannot perform multipart upload",
				{ code: "unsupported_runtime" },
			);
		}

		const source = internalBehaviorMapsValidateSource(req);
		const target = internalBehaviorMapsValidateTarget(req.target);
		const { file, label } = await materializeSource(source, {
			fetchImpl: this.fetchImpl,
			maxSourceBytes: this.maxSourceBytes,
			signal: req.signal,
			timeoutMs: this.timeoutMs,
		});

		const form = new FormData();
		form.append("file", file, label);
		form.append("strategy", target.strategy);
		if (target.strategy === "magic_hint") {
			form.append("hint", target.hint);
		}

		const res = await this.transport.request<BehaviorMapDirectUploadResult>({
			body: form,
			method: "POST",
			path: "/internal/behavior-maps/direct-upload",
			requestId: req.requestId,
			retryable: false,
			signal: req.signal,
		});

		return parseRes(
			behaviorMapDirectUploadResponse,
			res.data,
			"internal.behaviorMaps.directUpload",
		);
	}
}
